INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e3900b32-2448-49e9-a49f-95ea191601de',
  '00000000-0000-0000-0000-000000000001',
  $escape$Rust Benchmarking with Criterion — Measuring What Actually Matters$escape$,
  $escape$Rust's zero-cost abstractions mean performance lives in the details — iterator chains vs. manual loops, stack vs. heap allocation, branch prediction patterns. `criterion` is the de facto benchmarking harness: it runs statistical analysis across multiple samples, accounts for warm-up, and reports throughput, mean, and confidence intervals.

Define benchmarks under a `benches/` directory using `criterion_group!` and `criterion_main!`. Each closure receives a `Bencher` — call `b.iter(|| ...)` wrapping your hot path. Wrap return values in `std::hint::black_box()` to prevent the compiler from optimizing your benchmark target away entirely — a critical footgun unique to Rust's aggressive dead-code elimination.

For profiling, `cargo flamegraph` (via `perf` on Linux or `dtrace` on macOS) generates call-graph flame graphs from a single command. Pair with `RUSTFLAGS="-C force-frame-pointers=yes"` for accurate stack unwinding. Use `perf stat` to inspect cache misses and branch mispredictions at the hardware level — often more revealing than wall-clock time alone.$escape$,
  $escape$// benches/my_bench.rs
use criterion::{black_box, criterion_group, criterion_main, Criterion};

fn sum_iterators(data: &[u64]) -> u64 {
    data.iter().sum()
}

fn sum_manual(data: &[u64]) -> u64 {
    let mut acc = 0u64;
    for &x in data { acc += x; }
    acc
}

fn bench_sums(c: &mut Criterion) {
    let data: Vec<u64> = (0..10_000).collect();
    c.bench_function("iter_sum", |b| b.iter(|| sum_iterators(black_box(&data))));
    c.bench_function("manual_sum", |b| b.iter(|| sum_manual(black_box(&data))));
}

criterion_group!(benches, bench_sums);
criterion_main!(benches);$escape$,
  $escape$rust$escape$,
