INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '64ff4797-abc7-41b0-b7be-b907003bb8ab',
  '00000000-0000-0000-0000-000000000001',
  $escape$Rust Clippy — Lints That Actually Change How You Write Code$escape$,
  $escape$Clippy isn't just a formatter — it enforces idiomatic Rust at the semantic level. Running `cargo clippy -- -D warnings` treats every lint as a compile error, forcing you to address them. Key lints worth knowing: `clippy::needless_pass_by_value` catches function parameters that should be references. `clippy::map_unwrap_or` flags `.map(...).unwrap_or(...)` chains that should be `.map_or(...)`. `clippy::cloned_instead_of_copied` pushes you toward `.copied()` on types that implement `Copy`. For formatting, `rustfmt` with a `rustfmt.toml` lets you enforce `imports_granularity = "Module"` to group use statements cleanly. Pair it with `cargo fmt --check` in CI to block unformatted PRs. For pedantic lints, opt in explicitly in your crate root with `#![warn(clippy::pedantic)]` — these catch subtler issues like missing `#[must_use]` on functions returning `Result`. The real value is that Clippy teaches you idiomatic Rust iteratively: each lint explains why the alternative is more correct or efficient, not just stylistically different.$escape$,
  $escape$#![warn(clippy::pedantic)]

// Clippy: use `.map_or()` instead of `.map().unwrap_or()`
let val: Option<i32> = Some(5);

// flagged
let _a = val.map(|x| x * 2).unwrap_or(0);

// idiomatic
let _b = val.map_or(0, |x| x * 2);

// Clippy: use `.copied()` instead of `.cloned()` on Copy types
let nums = vec![1u32, 2, 3];
let _c: Vec<u32> = nums.iter().copied().collect();$escape$,
  $escape$rust$escape$,
