INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '40a23de6-df02-4722-8bf9-c1f39cadf47d',
  '00000000-0000-0000-0000-000000000001',
  $escape$Rust Deployment — Static Binaries, Scratch Images, and Zero Runtime Deps$escape$,
  $escape$Rust's lack of a runtime makes it uniquely suited for minimal container images. By default, `cargo build --release` dynamically links against glibc, which prevents `FROM scratch`. Retarget to `x86_64-unknown-linux-musl` for a fully static binary with zero host dependencies. Pair this with release profile tuning in `Cargo.toml`: `opt-level = "z"` minimizes size over speed, `lto = true` eliminates dead code across the entire crate graph, `codegen-units = 1` enables maximum LLVM optimization, and `strip = true` (stable since Rust 1.77) drops debug symbols automatically. A typical actix-web binary drops from ~12 MB to under 3 MB with these flags. In multi-stage Docker builds, copy the musl binary straight into `FROM scratch` — no libc, no shell, no package manager, minimal CVE surface. For workspaces, `cargo build -p api-server --release` targets only the relevant binary. If you need TLS, statically link `rustls` instead of OpenSSL to avoid the `libssl` dependency entirely.$escape$,
  $escape$# Cargo.toml
[profile.release]
opt-level = "z"
lto = true
codegen-units = 1
strip = true

# Dockerfile
FROM rust:1.77-alpine AS builder
RUN apk add --no-cache musl-dev
WORKDIR /app
COPY . .
RUN cargo build --release --target x86_64-unknown-linux-musl

FROM scratch
COPY --from=builder /app/target/x86_64-unknown-linux-musl/release/api /api
ENTRYPOINT ["/api"]$escape$,
  $escape$bash$escape$,
